.darma-loader-darma-custom-453 {color: var(--loader-color, #059669);
   display: inline-flex;
   gap: 5px;
}
.darma-loader-darma-custom-453:before, .darma-loader-darma-custom-453:after  {
  content: "";
   width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px inset currentColor;
   animation: 2s infinite linear;
   animation-name: darma-loader-darma-custom-453-l3-1,darma-loader-darma-custom-453-l3-2;
   animation-delay: -1s,0s }
.darma-loader-darma-custom-453:after  {
  --s: -1;
}
@keyframes darma-loader-darma-custom-453-l3-1  {
  0% {border-radius:50% 0 0 50%}
25% {border-radius:50% 50% 0 0 }
50% {border-radius:0 50% 50% 0 }
75% {border-radius:0 0 50% 50%}
100% {border-radius:50% 0 0 50%}
}
@keyframes darma-loader-darma-custom-453-l3-2 {
  0% {transform:scaleX(var(--s,1)) rotate(0deg)}
100% {transform:scaleX(var(--s,1)) rotate(-360deg)}
}

